package com.weaone.themoa.domain.customerservice.rag;

import org.springframework.stereotype.Component;

import java.util.List;

@Component
public class CustomerServiceGuideCatalog {

    public List<CustomerKnowledgeDocument> documents() {
        return List.of(
                guide("service-scope", "고객센터 챗봇 답변 범위", "고객센터 챗봇은 더모아 서비스 사용법, 고객센터 FAQ, 카드 연동, 하루 권장 소비액, 고정지출, 수기 지출, 계정 보안, 청년정책 기능 사용법, 금융상품 추천 기능 사용법만 안내한다. 실제 청년정책 추천 결과, 금융상품 가입 판단, 개인 소비 데이터 분석, 외부 최신 정보 생성은 처리하지 않고 해당 화면 또는 1:1 문의로 안내한다."),
                guide("policy-feature-start", "청년정책 추천 기능 시작 방법", "청년정책 추천은 대시보드의 정책 추천 화면에서 이용한다. 사용자는 자연어로 지역, 나이, 학생 여부, 취업 상태, 원하는 지원 분야를 입력할 수 있다. 지역 정보는 가입 시 필수가 아니며 정책 추천 화면 첫 진입 또는 검색 과정에서 입력받을 수 있다."),
                guide("policy-region", "정책 추천 지역 정보 사용 기준", "지역 기반 청년정책을 정확히 추천하기 위해 거주지 또는 근무지 지역 정보를 사용한다. 사용자가 지역을 명확히 입력하면 해당 지역과 호환되는 정책을 우선 찾고, 지역이 불명확하면 추가 확인이 필요하다고 안내한다. 지역 정보는 정책 추천 정확도를 높이는 목적으로 사용한다."),
                guide("policy-result", "정책 추천 결과 해석 안내", "정책 추천 결과는 더모아가 수집한 실제 정책 데이터와 검색 조건을 바탕으로 관련도가 높은 정책을 보여주는 참고 정보다. 최종 신청 가능 여부, 신청 기간, 제출 서류, 예산 소진 여부는 반드시 공식 기관 상세 페이지에서 확인해야 한다."),
                guide("policy-no-result", "정책 검색 결과가 없을 때 안내", "정책 검색 결과가 없으면 조건을 조금 넓혀 다시 검색하도록 안내한다. 예를 들어 지역을 시도 단위로 넓히거나, 나이/취업 상태/지원 분야 조건을 덜 구체적으로 입력해 볼 수 있다. 그래도 찾지 못하면 1:1 문의로 확인을 요청할 수 있다."),
                guide("policy-profile", "정책 추천 조건 입력 안내", "정책 추천 정확도를 높이려면 나이, 지역, 재학 여부, 취업 상태, 원하는 지원 목적을 함께 입력하는 것이 좋다. 예시는 '서울 사는 27살 취준생 주거 지원 정책', '부산 대학생 교통비 지원'처럼 쓸 수 있다."),
                guide("financial-feature-start", "금융상품 추천 기능 시작 방법", "금융상품 추천은 상품 추천 화면에서 이용한다. 예금, 적금, 대출, 연금 등 상품 조건을 비교해 볼 수 있으며, 사용자의 입력 조건과 서비스 내 소비/예산 맥락을 참고해 후보를 보여줄 수 있다. 고객센터 챗봇은 상품 사용법만 안내하고 특정 상품 가입을 권유하지 않는다."),
                guide("financial-result", "금융상품 추천 결과 해석 안내", "금융상품 추천 결과는 참고용이다. 금리, 우대조건, 가입 가능 여부, 중도해지 조건, 세금, 수수료 등은 금융기관의 공식 상품 설명과 약관에서 최종 확인해야 한다. 고객센터 챗봇은 최신 금리나 가입 결정을 대신 판단하지 않는다."),
                guide("daily-budget-formula", "하루 권장 소비액 계산 기준", "하루 권장 소비액은 월 예산에서 어제까지의 이번 급여주기 누적 순지출을 뺀 뒤 오늘을 포함한 남은 일수로 나누어 계산한다. 월 예산은 월급에서 고정지출 합계와 월 저축 목표를 뺀 값이다. 오늘 결제 내역은 다음 계산 시점부터 반영되어 당일 권장액이 중간에 흔들리지 않는다."),
                guide("salary-day-change", "급여일 변경 반영 기준", "급여일을 변경해도 진행 중인 급여주기는 그대로 유지된다. 변경한 급여일은 다음 급여주기부터 적용된다. 이미 시작된 주기의 예산과 하루 권장액을 소급해서 다시 계산하지 않는다."),
                guide("budget-change", "월급과 저축 목표 변경 반영 기준", "월급이나 저축 목표를 수정하면 이후 예산 계산에는 반영되지만 이미 확정되어 표시된 오늘 하루 권장액은 중간에 바뀌지 않는다. 다음 날 새 계산 시점부터 변경값이 반영된다."),
                guide("surplus", "남은 예산 이월 기준", "급여주기가 끝났을 때 남은 예산은 다음 달로 자동 이월되지 않는다. 새 급여주기는 다시 월급 기준으로 계산된다. 남은 잉여금은 저축 또는 금융상품 추천을 살펴보는 참고 신호로 사용할 수 있다."),
                guide("card-sync-start", "카드 연동 시작과 수집 기준", "카드 연동은 지원 카드사를 선택하고 카드사 인증을 거쳐 시작한다. 카드를 처음 연결하면 최근 결제 내역을 소급 수집할 수 있고 이후 자동 수집으로 소비 내역을 갱신한다. 카드사 점검, 인증 만료, 비밀번호 오류가 있으면 수집이 지연될 수 있다."),
                guide("card-sync-security", "카드 연동 보안 안내", "더모아 지원팀은 비밀번호나 카드사 원본 인증정보를 요구하지 않는다. 카드사 로그인 자격증명은 연결 과정에서만 사용하며 고객센터 답변이나 챗봇 대화로 입력받지 않는다. 민감정보를 포함한 문제는 1:1 문의에서도 필요한 범위만 작성하도록 안내한다."),
                guide("card-sync-lock", "카드사 비밀번호 오류와 잠금 안내", "카드사 비밀번호를 여러 번 잘못 입력하면 더모아가 일시적으로 재시도를 제한하거나 카드사 계정이 잠길 수 있다. 카드사 쪽 계정 잠금은 더모아가 해제할 수 없으며 카드사 앱, 홈페이지, 고객센터에서 본인 인증 후 해제해야 한다."),
                guide("fixed-expense-detect", "고정지출 자동 추천 기준", "고정지출은 같은 가맹점에서 최근 3개월 내 3회 이상, 매달 비슷한 날짜 주기, 유사한 금액으로 결제된 내역이 있을 때 후보로 추천될 수 있다. 카드 연동 직후에는 판단할 데이터가 부족해 추천이 바로 나오지 않을 수 있다."),
                guide("fixed-expense-matching", "고정지출 이중 차감 방지", "등록된 고정지출과 실제 카드 결제 내역이 매칭되면 하루 지출 합계에서 중복 차감되지 않도록 처리한다. 가맹점 표기가 다르거나 금액 차이가 큰 경우 매칭이 실패할 수 있으며 고정지출 화면에서 정정할 수 있다."),
                guide("manual-expense", "수기 지출 입력 기준", "현금과 계좌이체 지출은 카드사 자동 수집 대상이 아니므로 수기로 입력할 수 있다. 카드 자동수집이 켜져 있는 동안에는 중복 방지를 위해 카드 결제 수기 입력이 제한될 수 있다. 카드 연동 후 실제 카드 내역과 일치하는 수기 카드 지출은 정본 내역으로 대체될 수 있다."),
                guide("account-password", "비밀번호 변경과 로그아웃 기준", "비밀번호를 변경하면 계정 보안을 위해 접속 중이던 모든 기기에서 강제 로그아웃된다. 일반 로그아웃은 현재 기기의 세션만 종료한다. 분실 또는 도용이 의심되면 비밀번호 변경을 안내한다."),
                guide("account-delete", "회원 탈퇴 안내", "회원 탈퇴 시 등록된 카드사 연결 정보는 즉시 파기되고 자동 수집 대상에서 제외된다. 탈퇴 이후 복구가 어려울 수 있으므로 필요한 내역은 탈퇴 전에 확인하도록 안내한다."),
                guide("inquiry-handoff", "챗봇에서 1:1 문의로 넘기는 기준", "챗봇이 고객센터 지식 문서에서 충분한 근거를 찾지 못하거나, 사용자 개인 계정 상태 확인, 카드 연동 실패 원인 확인, 결제 내역 정정, 민감정보가 필요한 문제는 추측하지 않고 1:1 문의 접수로 안내한다.")
        );
    }

    private CustomerKnowledgeDocument guide(String id, String title, String content) {
        return new CustomerKnowledgeDocument("guide:" + id, CustomerKnowledgeSourceType.GUIDE,
                id, "사용가이드", title, content);
    }
}
